export enum ViewType {
  DASHBOARD = 'DASHBOARD',
  CHAT = 'CHAT',
  IMAGE_GEN = 'IMAGE_GEN',
  SETTINGS = 'SETTINGS'
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface GeneratedImage {
  url: string;
  prompt: string;
  timestamp: Date;
}

export interface AppState {
  currentView: ViewType;
  messages: ChatMessage[];
  images: GeneratedImage[];
  isThinking: boolean;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const chatWithGemini = async (history: { role: string; text: string }[], message: string) => {
  const ai = getAIClient();
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: 'You are Vikey, a smart AI personal assistant. Be concise, friendly, and helpful. You excel at productivity and creative tasks.',
    },
  });

  // Re-establish history if needed, though for simplicity we just send the message
  // In a full app, you might map history to the contents property
  const response: GenerateContentResponse = await chat.sendMessage({ message });
  return response.text;
};

export const generateImageWithGemini = async (prompt: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { text: prompt },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
      },
    },
  });

  for (const part of response.candidates?.[0]?.content.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }
  throw new Error('No image generated');
};

export const getSmartSummary = async (content: string) => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Summarize the following in 3 bullet points: ${content}`,
  });
  return response.text;
};

