export default ImageGenerator;

import React, { useState, useCallback } from 'react';
import { ViewType, ChatMessage, GeneratedImage } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Chat from './components/Chat';
import ImageGenerator from './components/ImageGenerator';
import { chatWithGemini } from './services/geminiService';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>(ViewType.DASHBOARD);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [images, setImages] = useState<GeneratedImage[]>([]);
  const [isThinking, setIsThinking] = useState(false);

  const handleSendMessage = async (text: string) => {
    const userMessage: ChatMessage = {
      role: 'user',
      text,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setIsThinking(true);

    try {
      const history = messages.map(m => ({ role: m.role, text: m.text }));
      const response = await chatWithGemini(history, text);

      const aiMessage: ChatMessage = {
        role: 'model',
        text: response || 'I am having trouble processing that right now.',
        timestamp: new Date()
      };
      setMessages(prev => [...prev, aiMessage]);
    } catch (error) {
      console.error('Chat error:', error);
      setMessages(prev => [...prev, {
        role: 'model',
        text: 'Sorry, I encountered an error connecting to my core processing unit.',
        timestamp: new Date()
      }]);
    } finally {
      setIsThinking(false);
    }
  };

  const handleImageGenerated = (img: GeneratedImage) => {
    setImages(prev => [img, ...prev]);
  };

  const renderView = () => {
    switch (currentView) {
      case ViewType.DASHBOARD:
        return (
          <Dashboard 
            onNavigate={setCurrentView} 
            messageCount={messages.length} 
            imageCount={images.length} 
          />
        );
      case ViewType.CHAT:
        return (
          <Chat 
            messages={messages} 
            onSendMessage={handleSendMessage} 
            isThinking={isThinking} 
          />
        );
      case ViewType.IMAGE_GEN:
        return (
          <ImageGenerator 
            images={images} 
            onImageGenerated={handleImageGenerated} 
          />
        );
      case ViewType.SETTINGS:
        return (
          <div className="flex flex-col items-center justify-center h-full text-slate-500">
             <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center mb-4">
               <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
             </div>
             <p className="text-lg">Settings interface coming soon</p>
          </div>
        );
      default:
        return <Dashboard onNavigate={setCurrentView} messageCount={messages.length} imageCount={images.length} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">
      <Sidebar currentView={currentView} onViewChange={setCurrentView} />

      <main className="flex-1 overflow-hidden relative">
        {/* Background blobs for aesthetics */}
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-600/10 blur-[120px] rounded-full -z-10 pointer-events-none"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full -z-10 pointer-events-none"></div>

        <div className="h-full overflow-y-auto custom-scrollbar">
          {renderView()}
        </div>
      </main>
    </div>
  );
};

export default App;

