  VISION = 'VISION',
  SETTINGS = 'SETTINGS',
  DEVELOPER = 'DEVELOPER',
  TEMPLATES = 'TEMPLATES'
}

export enum AppMode {
  DEFAULT = 'FahzGPT Default',
  MATH = 'FahzGPT Math',
  CODER = 'FahzGPT Coder',
  KOKI = 'FahzGPT Koki'
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  email: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface ChatSession {
  id: string;
  title: string;
  messages: ChatMessage[];
  lastModified: Date;
  mode: AppMode;
}

export interface GeneratedImage {
  url: string;
  prompt: string;
  timestamp: Date;
}

import { GoogleGenAI, Type, GenerateContentResponse, Modality } from "@google/genai";
import { AppMode } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

const getSystemInstruction = (mode: AppMode) => {
  const base = "Nama kamu adalah FahzGPT, asisten AI bertenaga model Fahz-Flash (Gemini 3 Flash Preview). Pembuat kamu adalah Fahz-Team OFFC. ";
  switch (mode) {
    case AppMode.MATH:
      return base + "Kamu adalah pakar Matematika. Fokuslah memberikan penjelasan matematis yang akurat dan langkah demi langkah.";
    case AppMode.CODER:
