import React from 'react';
import { ViewType, ChatSession, AppMode, User } from '../types';

interface SidebarProps {
  currentView: ViewType;
  onViewChange: (view: ViewType) => void;
  sessions: ChatSession[];
  activeSessionId: string | null;
  onSessionSelect: (id: string) => void;
  onNewChat: () => void;
  onDeleteSession: (id: string) => void;
  onRenameSession: (id: string, newTitle: string) => void;
  currentMode: AppMode;
  onModeChange: (mode: AppMode) => void;
  isOpen: boolean;
  onClose: () => void;
  onLogout: () => void;
  user: User;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  currentView, onViewChange, sessions, activeSessionId, 
  onSessionSelect, onNewChat, onDeleteSession, onRenameSession,
  currentMode, onModeChange, isOpen, onClose, onLogout, user
}) => {
  const menuItems = [
    { id: ViewType.VISION, label: 'Vision Creator', icon: '🎨' },
    { id: ViewType.TEMPLATES, label: 'Code Templates', icon: '📄' },
    { id: ViewType.SETTINGS, label: 'Settings', icon: '⚙️' },
    { id: ViewType.DEVELOPER, label: 'Developer', icon: '👨‍💻' },
  ];

  return (
    <>
      {/* Mobile Overlay */}
      <div 
        className={`fixed inset-0 bg-black/60 z-40 transition-opacity md:hidden ${isOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}
        onClick={onClose}
      />

      <div className={`fixed md:static inset-y-0 left-0 w-72 md:w-64 bg-[#171717] flex flex-col border-r border-white/5 transition-transform duration-300 z-50 ${isOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <div className="p-3 flex items-center justify-between">
          <button 
            onClick={onNewChat}
            className="flex-1 flex items-center justify-between px-3 py-2.5 rounded-lg border border-white/10 hover:bg-white/5 transition-colors text-white font-medium text-sm group"
          >
            <div className="flex items-center gap-2">
              <div className="w-6 h-6 rounded bg-white text-black flex items-center justify-center font-bold text-xs italic">F</div>
              New Chat
            </div>
            <svg className="w-4 h-4 text-slate-400 group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
          </button>

          <button onClick={onClose} className="p-2 ml-2 md:hidden text-slate-400 hover:text-white">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar px-3 space-y-1 py-2">
          <p className="px-3 text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">History</p>
          {sessions.map(s => (
            <div 
              key={s.id}
              className={`group flex items-center gap-2 px-3 py-2 rounded-lg text-sm cursor-pointer transition-colors ${activeSessionId === s.id ? 'bg-[#212121] text-white' : 'text-slate-400 hover:bg-[#212121] hover:text-slate-200'}`}
              onClick={() => {
                onSessionSelect(s.id);
                onViewChange(ViewType.CHAT);
              }}
            >
              <span className="flex-1 truncate">{s.title}</span>
              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    const newTitle = prompt('Rename chat:', s.title);
                    if (newTitle) onRenameSession(s.id, newTitle);
                  }}
                  className="p-1 hover:text-white"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                </button>
                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    if (confirm('Delete this chat?')) onDeleteSession(s.id);
                  }}
                  className="p-1 hover:text-red-400"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                </button>
              </div>
            </div>
          ))}
          {sessions.length === 0 && <p className="px-3 text-xs text-slate-600">No recent chats</p>}

          <div className="pt-6 pb-2">
            <p className="px-3 text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Modes</p>
            {Object.values(AppMode).map(mode => (
              <button
                key={mode}
                onClick={() => onModeChange(mode)}
                className={`w-full text-left px-3 py-1.5 rounded-lg text-xs transition-colors ${currentMode === mode ? 'bg-indigo-500/10 text-indigo-400 font-bold' : 'text-slate-500 hover:text-slate-300'}`}
              >
                • {mode}
              </button>
            ))}
          </div>
        </div>

        <div className="mt-auto p-3 space-y-1">
          {menuItems.map(item => (
            <button
              key={item.id}
              onClick={() => onViewChange(item.id)}
              className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg text-sm transition-colors ${currentView === item.id ? 'bg-[#212121] text-white' : 'text-slate-400 hover:bg-[#212121] hover:text-slate-200'}`}
            >
              <span className="text-lg">{item.icon}</span>
              {item.label}
            </button>
          ))}
          <div className="pt-2 border-t border-white/5 mt-2">
            <div className="px-3 py-2 flex items-center justify-between group">
               <div className="flex items-center gap-3 min-w-0">
                  <div className="w-8 h-8 rounded-full vikey-gradient flex items-center justify-center text-[10px] font-bold shrink-0">FAHZ</div>
                  <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium text-white truncate">{user.name}</p>
                      <p className="text-[10px] text-slate-500 truncate">Premium Account</p>
                  </div>
               </div>
               <button 
                onClick={onLogout}
                className="p-2 text-slate-500 hover:text-red-400 transition-colors"
                title="Logout"
               >
                 <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
               </button>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default Sidebar;

import React, { useState, useRef, useEffect } from 'react';
import { ChatSession, AppMode, ChatAttachment } from '../types';
import CodeBlock from './CodeBlock';

interface ChatViewProps {
  session: ChatSession;
  onSendMessage: (text: string, attachment?: ChatAttachment) => void;
  isThinking: boolean;
  onOpenCall: () => void;
  mode: AppMode;
  onToggleSidebar: () => void;
}

const ChatView: React.FC<ChatViewProps> = ({ session, onSendMessage, isThinking, onOpenCall, mode, onToggleSidebar }) => {
  const [input, setInput] = useState('');
  const [attachment, setAttachment] = useState<ChatAttachment | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [session.messages, isThinking]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() && !attachment) return;
    if (isThinking) return;
    onSendMessage(input, attachment || undefined);
    setInput('');
    setAttachment(null);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    const isImage = file.type.startsWith('image/');

    reader.onload = (event) => {
      const result = event.target?.result as string;
      setAttachment({
        type: isImage ? 'image' : 'file',
        name: file.name,
        data: result,
        mimeType: file.type
      });
    };

    if (isImage) {
      reader.readAsDataURL(file);
    } else {
      reader.readAsText(file);
    }
    // Reset input so same file can be selected again
    e.target.value = '';
  };

  const renderContent = (text: string) => {
    const parts = text.split(/```/);
    return parts.map((part, i) => {
      if (i % 2 === 1) {
        const lines = part.split('\n');
        const lang = lines[0].trim() || 'txt';
        const code = lines.slice(1).join('\n').trim();
        return <CodeBlock key={i} code={code} language={lang} />;
      }
      return <p key={i} className="whitespace-pre-wrap">{part}</p>;
    });
  };

  return (
    <div className="flex flex-col h-full bg-[#212121]">
      <div className="h-14 flex items-center justify-between px-4 border-b border-white/5 bg-[#212121]">
        <div className="flex items-center gap-2">
           <button onClick={onToggleSidebar} className="p-2 -ml-2 text-slate-400 md:hidden hover:text-white transition-colors">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" /></svg>
           </button>
           <div className="flex flex-col md:flex-row md:items-center md:gap-2">
              <span className="text-white font-bold text-xs md:text-sm tracking-tight">{mode}</span>
              <span className="hidden md:inline text-[10px] bg-indigo-500/20 text-indigo-400 px-1.5 py-0.5 rounded font-bold">FAHZ-FLASH</span>
           </div>
        </div>
        <button 
          onClick={onOpenCall}
          className="p-2 hover:bg-white/10 rounded-lg text-slate-300 transition-colors"
          title="Voice Call"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z" /></svg>
        </button>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-8 max-w-3xl mx-auto w-full">
        {session.messages.length === 0 && (
           <div className="h-full flex flex-col items-center justify-center text-center py-20">
              <div className="w-16 h-16 rounded-2xl vikey-gradient flex items-center justify-center text-3xl font-black italic shadow-2xl mb-6">F</div>
              <h1 className="text-2xl font-bold text-white mb-2">How can I help you?</h1>
              <p className="text-slate-500 text-sm italic">FahzGPT bertenaga Gemini 3 Flash Preview</p>
           </div>
        )}

        {session.messages.map((m) => (
          <div key={m.id} className="flex gap-4">
            <div className={`w-8 h-8 rounded-full shrink-0 flex items-center justify-center text-xs font-bold ${m.role === 'user' ? 'bg-slate-700 text-white' : 'vikey-gradient text-white italic'}`}>
              {m.role === 'user' ? 'U' : 'F'}
            </div>
            <div className="flex-1 text-slate-200 text-sm leading-7 pt-1 min-w-0">
              <p className="font-bold text-xs text-slate-500 uppercase mb-1">{m.role === 'user' ? 'You' : 'FahzGPT'}</p>

              {m.attachment && (
                <div className="mb-4">
                  {m.attachment.type === 'image' ? (
                    <img src={m.attachment.data} alt="Attached" className="max-w-full max-h-64 rounded-xl border border-white/10" />
                  ) : (
                    <div className="inline-flex items-center gap-2 p-3 bg-slate-800 rounded-xl border border-white/5">
                      <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
                      <span className="text-xs font-medium truncate max-w-[200px]">{m.attachment.name}</span>
                    </div>
                  )}
                </div>
              )}

              <div className="break-words">
                {renderContent(m.text)}
              </div>
            </div>
          </div>
        ))}
        {isThinking && (
          <div className="flex gap-4 animate-pulse">
            <div className="w-8 h-8 rounded-full bg-indigo-500/20 shrink-0"></div>
            <div className="flex-1 space-y-2">
              <div className="h-2 bg-white/5 rounded w-3/4"></div>
              <div className="h-2 bg-white/5 rounded w-1/2"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-gradient-to-t from-[#212121] via-[#212121] to-transparent">
        <div className="max-w-3xl mx-auto">
          {attachment && (
            <div className="mb-2 p-2 bg-[#2f2f2f] rounded-xl flex items-center gap-3 border border-indigo-500/30">
               {attachment.type === 'image' ? (
                 <div className="w-10 h-10 rounded-lg overflow-hidden border border-white/10 shrink-0">
                    <img src={attachment.data} alt="Preview" className="w-full h-full object-cover" />
                 </div>
               ) : (
                 <div className="w-10 h-10 rounded-lg bg-indigo-500/20 flex items-center justify-center shrink-0">
                    <svg className="w-5 h-5 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                 </div>
               )}
               <div className="flex-1 min-w-0">
                  <p className="text-xs font-medium text-white truncate">{attachment.name}</p>
                  <p className="text-[10px] text-slate-500">Ready to upload</p>
               </div>
               <button onClick={() => setAttachment(null)} className="p-1 hover:text-white text-slate-500">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
               </button>
            </div>
          )}

          <form onSubmit={handleSubmit} className="relative group flex items-end gap-2">
            <div className="flex-1 relative flex items-center">
              <button 
                type="button" 
                onClick={() => fileInputRef.current?.click()}
                className="absolute left-3 p-1.5 rounded-lg text-slate-400 hover:text-white transition-colors"
                title="Upload file"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
              </button>
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Message FahzGPT..."
                className="w-full bg-[#2f2f2f] text-white rounded-2xl py-3 pl-12 pr-12 focus:outline-none focus:ring-1 focus:ring-white/20 transition-all border border-transparent resize-none h-14"
                onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSubmit(e); } }}
              />
              <button
                type="submit"
                disabled={(!input.trim() && !attachment) || isThinking}
                className="absolute right-3 p-1.5 rounded-lg bg-white text-black disabled:opacity-30 transition-opacity"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
              </button>
            </div>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              onChange={handleFileChange}
              accept="image/*,.txt,.js,.py,.html,.css,.json" 
            />
          </form>
          <p className="text-[10px] text-slate-500 text-center mt-3">
            FahzGPT can make mistakes. Check important info.
          </p>
        </div>
      </div>
    </div>
  );
};

export default ChatView;

